      if (!presignResponse.ok) throw new Error('Failed to get upload permission');
      const { uploadUrl, key, publicUrl } = await presignResponse.json();

      const uploadResponse = await fetch(uploadUrl, {
          method: 'PUT',
          body: file,
          headers: { 'Content-Type': file.type }
