// Determine Base URL
const getBaseUrl = () => {
    if (typeof window === 'undefined') return '';
    const host = window.location.hostname;
    if (host === 'localhost' || host === '127.0.0.1') return 'http://localhost:3001';
    return ''; 
};

const API_BASE_URL = getBaseUrl();

const fetchWithRetry = async (url: string, options?: RequestInit, retries = 3, delay = 500): Promise<Response> => {
    try {
        const response = await fetch(url, options);
        if (!response.ok) {
             if (response.status >= 500) {
                 if (retries > 0) {
                     await new Promise(res => setTimeout(res, delay));
                     return fetchWithRetry(url, options, retries - 1, delay * 2);
                 }
                 // Try to get JSON error body if available
                 let errMessage = `Server Error: ${response.status}`;
                 try {
                     const errData = await response.json();
                     if (errData.error) errMessage = errData.error;
                 } catch(e) {}
                 throw new Error(errMessage);
             }
             // For 4xx errors, parse body immediately
             let errMessage = `Request Failed: ${response.status}`;
             try {
                 const errData = await response.json();
                 if (errData.error) errMessage = errData.error;
             } catch(e) {}
             throw new Error(errMessage);
        }
        return response;
    } catch (err: any) {
        if (retries > 0 && !err.message.includes('4')) { // Don't retry 4xx
            await new Promise(res => setTimeout(res, delay));
            return fetchWithRetry(url, options, retries - 1, delay * 2); 
        }
        throw err;
    }
};

