export const BotBuilder = ({ isLiveMode }: { isLiveMode: boolean }) => {
    return (
        <ReactFlowProvider>
            <FlowEditor isLiveMode={isLiveMode} />
        </ReactFlowProvider>
    );
};

const FlowEditor = ({ isLiveMode }: { isLiveMode: boolean }) => {
    const { 
        nodes, edges, onNodesChange, onEdgesChange, onConnect, 
        setNodes, setEdges, addNode, updateNodeData, resetFlow
    } = useFlowStore();

    const [selectedNodeId, setSelectedNodeId] = useState<string | null>(null);
    const [isSaving, setIsSaving] = useState(false);
    const [isLoading, setIsLoading] = useState(true);
    const [loadError, setLoadError] = useState<string | null>(null);

    const loadData = useCallback(async () => {
        setIsLoading(true);
        setLoadError(null);
        try {
            const settings = isLiveMode ? await liveApiService.getBotSettings() : mockBackend.getBotSettings();
            if (settings.flowData && settings.flowData.nodes.length > 0) {
                const cleanNodes = settings.flowData.nodes.map((n: any) => {
                    const { icon, ...cleanData } = n.data || {};
                    return { ...n, data: cleanData };
                });
                setNodes(cleanNodes);
                setEdges(settings.flowData.edges);
            } else {
                resetFlow(); 
            }
        } catch (e: any) {
            setLoadError(e.message || "Failed to load bot flow");
        } finally {
            setIsLoading(false);
        }
    }, [isLiveMode, setNodes, setEdges, resetFlow]);

    useEffect(() => { loadData(); }, [loadData]);

    const onDragOver = useCallback((event: React.DragEvent) => { event.preventDefault(); event.dataTransfer.dropEffect = 'move'; }, []);
    const onDrop = useCallback((event: React.DragEvent) => {
        event.preventDefault();
        const type = event.dataTransfer.getData('application/reactflow/type');
        let inputType = event.dataTransfer.getData('application/reactflow/inputType');
        const label = event.dataTransfer.getData('application/reactflow/label');
        if (!type) return;

        const position = { x: event.clientX - 300, y: event.clientY };
        const newNode: Node = {
            id: `node_${Date.now()}`,
            type: 'custom',
            position,
            data: { 
                label, 
                message: '', 
                inputType,
                buttons: [], // Init for cards
                headerImageUrl: '',
                templateName: '',
                delay: 0
            },
        };
        addNode(newNode);
        setSelectedNodeId(newNode.id);
    }, [addNode]);

    const handleSave = async () => {
        setIsSaving(true);
        const compiledSteps: BotStep[] = [];
        const startEdge = edges.find(e => e.source === 'start');
        let entryPointId = startEdge?.target;

        nodes.forEach(node => {
            const data = node.data as any;
            if (data.type === 'start') return;

            const outgoingEdges = edges.filter(e => e.source === node.id);
            let nextStepId: string | undefined = 'END'; 
            let routes: Record<string, string> = {};

            const mainEdge = outgoingEdges.find(e => e.sourceHandle === 'main' || !e.sourceHandle);
            if (mainEdge) nextStepId = mainEdge.target;

            // Handle Reply Buttons Routing
            if (data.buttons) {
                data.buttons.forEach((btn: MessageButton, idx: number) => {
                    if (btn.type === 'reply') {
                        const handleId = `btn-${idx}`;
                        const edge = outgoingEdges.find(e => e.sourceHandle === handleId);
                        if (edge) routes[btn.title] = edge.target;
                    }
                });
            }

            // Legacy Options Routing
            if (data.options) {
                data.options.forEach((opt: string, idx: number) => {
                     const handleId = `option-${idx}`;
                     const edge = outgoingEdges.find(e => e.sourceHandle === handleId);
                     if (edge) routes[opt] = edge.target;
                });
            }

            const { icon, ...cleanData } = data;

            // CLEANING DATA TO ENSURE CORRECT SERVER PROCESSING
            // If it's a simple text message, remove interaction triggers so server auto-advances
            if (cleanData.label === 'Text Message') {
                delete cleanData.options;
                delete cleanData.saveToField;
                // keep delay
            }

            compiledSteps.push({
                id: node.id,
                title: cleanData.label,
                message: cleanData.message || "",
                inputType: cleanData.inputType,
                options: cleanData.options,
                buttons: cleanData.buttons,
                headerImageUrl: cleanData.headerImageUrl,
                footerText: cleanData.footerText,
                templateName: cleanData.templateName,
                delay: cleanData.delay,
                saveToField: cleanData.saveToField,
                nextStepId, 
                routes: Object.keys(routes).length > 0 ? routes : undefined, 
                mediaUrl: cleanData.mediaUrl,
                linkLabel: cleanData.linkLabel
            });
        });

        if (!entryPointId && compiledSteps.length > 0) entryPointId = compiledSteps[0].id;

        try {
            const currentSettings = isLiveMode ? await liveApiService.getBotSettings() : mockBackend.getBotSettings();
            const newSettings: BotSettings = {
                ...currentSettings,
                steps: compiledSteps,
                entryPointId,
                flowData: { nodes: nodes.map(n => ({...n, data: { ...n.data, icon: undefined }})), edges }
            };

            if (isLiveMode) await liveApiService.saveBotSettings(newSettings);
            else mockBackend.updateBotSettings(newSettings);
        } catch (e) { 
            alert("Save failed. Please check connection."); 
        } finally {
            setIsSaving(false);
        }
    };

    const selectedNode = useMemo(() => nodes.find(n => n.id === selectedNodeId), [nodes, selectedNodeId]);

    if (isLoading) return <div className="flex h-full items-center justify-center bg-slate-50"><Loader2 size={48} className="text-blue-600 animate-spin" /></div>;

    return (
        <div className="flex h-full bg-slate-50 font-sans relative overflow-hidden">
            <div className="w-64 bg-white border-r border-gray-200 flex flex-col z-10 shadow-lg">
                <div className="p-5 border-b border-gray-100">
                    <h2 className="font-bold text-gray-900 flex items-center gap-2 text-lg"><Zap className="text-yellow-500 fill-yellow-500" size={20} /> Bot Studio</h2>
                </div>
                <div className="flex-1 overflow-y-auto p-4 space-y-6">
                    <div>
                        <h4 className="text-[10px] font-bold text-gray-400 uppercase mb-3 tracking-wider">Rich Content</h4>
                        <div className="space-y-2">
                            <DraggableSidebarItem type="card" inputType="card" label="Rich Card" icon={<CreditCard size={16} />} />
                            <DraggableSidebarItem type="image" label="Image" icon={<ImageIcon size={16} />} />
                            <DraggableSidebarItem type="video" label="Video" icon={<Video size={16} />} />
                        </div>
                    </div>
                    <div>
                        <h4 className="text-[10px] font-bold text-gray-400 uppercase mb-3 tracking-wider">Basic</h4>
                        <div className="space-y-2">
                            <DraggableSidebarItem type="text" label="Text Message" icon={<MessageSquare size={16} />} />
                            <DraggableSidebarItem type="option" inputType="option" label="Question" icon={<GitBranch size={16} />} />
                            <DraggableSidebarItem type="input" inputType="text" label="Collect Text" icon={<Type size={16} />} />
                        </div>
                    </div>
                </div>
            </div>

            <div className="flex-1 relative h-full flex flex-col">
                <div className="absolute top-4 right-4 z-20 flex gap-2">
                    <button onClick={handleSave} disabled={isSaving} className="bg-black text-white px-5 py-2.5 rounded-full text-sm font-bold shadow-lg hover:bg-gray-800 transition-all flex items-center gap-2">
                        {isSaving ? <span className="animate-spin"><Zap size={16} /></span> : <CheckCircle size={16} />}
                        {isSaving ? 'Publishing...' : 'Publish Flow'}
                    </button>
                </div>

                <div className="flex-1 h-full" onDragOver={onDragOver} onDrop={onDrop}>
                    <ReactFlow
                        nodes={nodes}
                        edges={edges}
                        onNodesChange={onNodesChange}
                        onEdgesChange={onEdgesChange}
                        onConnect={onConnect}
                        nodeTypes={{ custom: NodePreviewCard }}
                        onNodeClick={(_, node) => setSelectedNodeId(node.id)}
                        onPaneClick={() => setSelectedNodeId(null)}
                        defaultViewport={{ x: 0, y: 0, zoom: 0.8 }}
                        minZoom={0.2} maxZoom={1.5}
                        fitView
                    >
                        <Background color="#cbd5e1" gap={20} size={1} variant={BackgroundVariant.Dots} />
                        <Controls className="bg-white border border-gray-200 shadow-xl rounded-lg p-1" />
                        <MiniMap className="border border-gray-200 rounded-lg shadow-xl" nodeColor="#3b82f6" maskColor="rgba(240, 242, 245, 0.7)" />
                    </ReactFlow>
                </div>
            </div>

            {selectedNode && (
                <PropertyInspector 
                    selectedNode={selectedNode} 
                    onChange={updateNodeData} 
                />
            )}
        </div>
    );
};

import React, { useState, useMemo } from 'react';
import { Driver, LeadStatus, MessageButton } from '../types';
import { 
  Search, Filter, Send, MessageSquare, CheckCircle, 
  AlertCircle, X, Users, ChevronLeft, ChevronRight, 
  MoreHorizontal, Phone, Mail, FileText, Zap, Paperclip, Cloud, Trash2, Plus, GitBranch,
  Globe, MapPin, CreditCard, LayoutTemplate, Clock
} from 'lucide-react';
import { MediaSelectorModal } from './MediaSelectorModal';
import { liveApiService } from '../services/liveApiService'; // Imported Service

interface LeadManagerProps {
  drivers: Driver[];
  onSelectDriver: (driver: Driver) => void;
  onBulkSend: (ids: string[], message: string, mediaUrl?: string, mediaType?: string, options?: string[], templateName?: string, scheduledTime?: number) => void;
  onUpdateDriverStatus: (ids: string[], status: LeadStatus) => void;
}

const ITEMS_PER_PAGE = 15;

export const LeadManager: React.FC<LeadManagerProps> = ({ 
  drivers, 
  onSelectDriver, 
  onBulkSend,
  onUpdateDriverStatus
}) => {
  const [activeSection, setActiveSection] = useState<string>('All');
  const [searchTerm, setSearchTerm] = useState('');
  const [currentPage, setCurrentPage] = useState(1);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [showBulkCompose, setShowBulkCompose] = useState(false);

  // Compose State
  const [bulkMessage, setBulkMessage] = useState('');
  const [selectedMedia, setSelectedMedia] = useState<{url: string, type: 'image' | 'video' | 'document'} | null>(null);
  const [showMediaPicker, setShowMediaPicker] = useState(false);
  const [showOptions, setShowOptions] = useState(false);
  const [templateName, setTemplateName] = useState('');

  // Scheduling State
  const [isScheduled, setIsScheduled] = useState(false);
  const [scheduleTime, setScheduleTime] = useState('');

  // Buttons State
  const [buttons, setButtons] = useState<MessageButton[]>([]);

  // --- SECTIONS CONFIG ---
  const sections = [
    { id: 'All', label: 'All Leads', icon: Users, color: 'text-gray-600' },
    { id: LeadStatus.NEW, label: 'New Inquiries', icon: Zap, color: 'text-blue-600' },
    { id: LeadStatus.QUALIFIED, label: 'Qualified', icon: CheckCircle, color: 'text-green-600' },
    { id: LeadStatus.FLAGGED_FOR_REVIEW, label: 'Flagged', icon: AlertCircle, color: 'text-amber-600' },
    { id: LeadStatus.REJECTED, label: 'Rejected', icon: X, color: 'text-red-600' },
    { id: LeadStatus.ONBOARDED, label: 'Onboarded', icon: FileText, color: 'text-purple-600' },
  ];

  // --- FILTERING ---
  const filteredDrivers = useMemo(() => {
    return drivers.filter(d => {
      const matchesSearch = d.name.toLowerCase().includes(searchTerm.toLowerCase()) || d.phoneNumber.includes(searchTerm);
      const matchesSection = activeSection === 'All' || d.status === activeSection;
      return matchesSearch && matchesSection;
    });
  }, [drivers, activeSection, searchTerm]);

  const totalPages = Math.ceil(filteredDrivers.length / ITEMS_PER_PAGE);
  const paginatedDrivers = filteredDrivers.slice(
    (currentPage - 1) * ITEMS_PER_PAGE,
    currentPage * ITEMS_PER_PAGE
  );

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) setSelectedIds(filteredDrivers.map(d => d.id));
    else setSelectedIds([]);
  };

  const handleSelectOne = (id: string) => {
    if (selectedIds.includes(id)) setSelectedIds(prev => prev.filter(sid => sid !== id));
    else setSelectedIds(prev => [...prev, id]);
  };

  const executeBulkSend = async () => {
    if (!bulkMessage.trim() && !selectedMedia && !templateName) return;

    // Default to NOW if not explicitly scheduled, using the robust scheduler backend
    const timestamp = isScheduled && scheduleTime ? new Date(scheduleTime).getTime() : Date.now();

    try {
        await liveApiService.scheduleMessage(selectedIds, {
            text: bulkMessage,
            mediaUrl: selectedMedia?.url,
            mediaType: selectedMedia?.type,
            buttons: buttons.length > 0 ? (buttons as any) : undefined,
            templateName: templateName || undefined
        }, timestamp);

        // Notify parent to show success toast
        onBulkSend(
            selectedIds, 
            bulkMessage, 
            selectedMedia?.url, 
            selectedMedia?.type, 
            buttons.length > 0 ? (buttons as any) : undefined,
            templateName || undefined,
            timestamp
        );
    } catch (e) {
        console.error(e);
        alert("Failed to schedule broadcast");
        return;
    }

    setShowBulkCompose(false);
    setBulkMessage('');
    setTemplateName('');
    setSelectedMedia(null);
    setButtons([]);
    setShowOptions(false);
    setIsScheduled(false);
    setScheduleTime('');
    setSelectedIds([]);
  };

  const executeBulkStatusUpdate = (status: LeadStatus) => {
      if(window.confirm(`Move ${selectedIds.length} leads to ${status}?`)) {
          onUpdateDriverStatus(selectedIds, status);
          setSelectedIds([]);
      }
  };

  const addButton = () => {
      if (buttons.length < 3) setButtons([...buttons, { type: 'reply', title: 'New Button' }]);
  };

  const updateButton = (index: number, field: keyof MessageButton, value: string) => {
      const newBtns = [...buttons];
      newBtns[index] = { ...newBtns[index], [field]: value };
      setButtons(newBtns);
  };

  const removeButton = (index: number) => {
      setButtons(buttons.filter((_, i) => i !== index));
  };

  return (
    <div className="flex h-[calc(100vh-100px)] bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">

      {/* SIDEBAR */}
      <div className="w-64 bg-gray-50 border-r border-gray-200 flex flex-col shrink-0">
        <div className="p-5 border-b border-gray-200">
           <h2 className="font-bold text-gray-800">Lead Sections</h2>
           <p className="text-xs text-gray-500 mt-1">Organize & Broadcast</p>
        </div>
        <nav className="flex-1 overflow-y-auto p-3 space-y-1">
          {sections.map(section => {
            const count = section.id === 'All' ? drivers.length : drivers.filter(d => d.status === section.id).length;
            const Icon = section.icon;
            const isActive = activeSection === section.id;

            return (
              <button
                key={section.id}
                onClick={() => { setActiveSection(section.id); setCurrentPage(1); setSelectedIds([]); }}
                className={`w-full flex items-center justify-between px-3 py-3 rounded-xl text-sm font-medium transition-all ${
                  isActive ? 'bg-white shadow-sm text-gray-900 border border-gray-200' : 'text-gray-500 hover:bg-gray-100'
                }`}
              >
                <div className="flex items-center gap-3">
                  <Icon size={18} className={isActive ? section.color : 'text-gray-400'} />
                  {section.label}
                </div>
                <span className={`text-xs px-2 py-0.5 rounded-full ${isActive ? 'bg-gray-100 text-gray-900 font-bold' : 'bg-gray-200/50 text-gray-500'}`}>{count}</span>
              </button>
            );
          })}
        </nav>
      </div>

      {/* MAIN CONTENT */}
      <div className="flex-1 flex flex-col min-w-0">
        <div className="p-4 border-b border-gray-200 flex items-center justify-between gap-4">
           <div className="flex items-center gap-2 bg-gray-50 px-3 py-2.5 rounded-xl border border-gray-200 flex-1 max-w-md focus-within:ring-2 focus-within:ring-blue-500/20 transition-all">
              <Search size={18} className="text-gray-400" />
              <input type="text" placeholder="Search by name or phone..." className="bg-transparent border-none outline-none w-full text-sm" value={searchTerm} onChange={(e) => { setSearchTerm(e.target.value); setCurrentPage(1); }} />
           </div>
           <div className="flex items-center gap-2 text-sm text-gray-500"><span>{filteredDrivers.length} Leads found</span></div>
        </div>

        <div className="bg-gray-50/50 border-b border-gray-200 flex items-center px-6 py-3 text-xs font-semibold text-gray-500 uppercase tracking-wider">
           <div className="w-10">
              <input type="checkbox" className="rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer" checked={selectedIds.length > 0 && selectedIds.length === filteredDrivers.length} onChange={handleSelectAll} />
           </div>
           <div className="flex-1">Driver Details</div>
           <div className="w-32 hidden md:block">Source</div>
           <div className="w-32">Status</div>
           <div className="w-40 text-right">Actions</div>
        </div>

        <div className="flex-1 overflow-y-auto">
           {paginatedDrivers.map(driver => (
             <div key={driver.id} onClick={() => onSelectDriver(driver)} className={`group flex items-center px-6 py-4 border-b border-gray-100 hover:bg-blue-50/30 transition-colors cursor-pointer ${selectedIds.includes(driver.id) ? 'bg-blue-50/50' : ''}`}>
                <div className="w-10" onClick={(e) => e.stopPropagation()}>
                    <input type="checkbox" className="rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer" checked={selectedIds.includes(driver.id)} onChange={() => handleSelectOne(driver.id)} />
                </div>
                <div className="flex-1 min-w-0 pr-4">
                   <div className="flex items-center gap-2">
                       <span className="font-bold text-gray-900 truncate">{driver.name}</span>
                       {driver.isBotActive && <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse" title="Bot Active"></span>}
                   </div>
                   <div className="text-xs text-gray-500 flex items-center gap-3 mt-1">
                      <span className="flex items-center gap-1"><Phone size={10} /> {driver.phoneNumber}</span>
                      <span className="hidden sm:inline text-gray-300">|</span>
                      <span className="hidden sm:inline truncate max-w-[200px]">{driver.lastMessage}</span>
                   </div>
                </div>
                <div className="w-32 hidden md:flex items-center">
                    <span className={`text-[10px] px-2 py-1 rounded-md font-medium border ${driver.source === 'Meta Ad' ? 'bg-blue-50 text-blue-700 border-blue-100' : 'bg-gray-50 text-gray-600 border-gray-100'}`}>{driver.source}</span>
                </div>
                <div className="w-32">
                    <span className={`inline-flex items-center px-2.5 py-0.5 rounded-full text-[10px] font-bold uppercase tracking-wide border ${driver.status === LeadStatus.NEW ? 'bg-blue-100 text-blue-800 border-blue-200' : driver.status === LeadStatus.QUALIFIED ? 'bg-green-100 text-green-800 border-green-200' : 'bg-gray-100 text-gray-800 border-gray-200'}`}>{driver.status}</span>
