        });
        console.log(`Loaded Credentials - PhoneID: ${PHONE_NUMBER_ID ? '***' + PHONE_NUMBER_ID.slice(-4) : 'Missing'}`);

        isDbInitialized = true;
        console.log("Database initialized (Lazy with Migrations & Default Flow)");
