    const updates = req.body;
    try {
        const allowed = ['status', 'notes', 'name', 'vehicle_registration', 'availability', 'is_bot_active', 'is_human_mode', 'qualification_checks'];
        for (const key of Object.keys(updates)) {
            if (allowed.includes(key)) {
