                await queryWithRetry(`UPDATE drivers SET ${key} = $1, updated_at = $3 WHERE id = $2`, [val, id, Date.now()]);
            }
        }
        res.json({ success: true });
    } catch(e) { res.status(500).json({ error: e.message }); }
});

